from qdrant_client import QdrantClient
from qdrant_client.models import Distance, VectorParams, SparseVectorParams, SparseIndexParams
from fastembed import TextEmbedding, SparseTextEmbedding

client = QdrantClient("http://127.0.0.1:6333")

# Create collection with hybrid search support
client.create_collection(
    collection_name="documents",
    vectors_config=VectorParams(size=384, distance=Distance.COSINE),
    sparse_vectors_config={
        "text": SparseVectorParams(
            index=SparseIndexParams(on_disk=False)
        )
    }
)

# Initialize embedding models
dense_model = TextEmbedding("BAAI/bge-small-en-v1.5")
sparse_model = SparseTextEmbedding("Qdrant/bm25")

# Ingest documents
docs = ["RAG combines retrieval with generation", "Vector databases enable semantic search"]
for i, doc in enumerate(docs):
    dense_vec = list(dense_model.embed([doc]))[0]
    sparse_vec = list(sparse_model.embed([doc]))[0]
    client.upsert(
        collection_name="documents",
        points=[{
            "id": i,
            "vector": {"dense": dense_vec.tolist(), "text": sparse_vec.as_object()},
            "payload": {"text": doc}
        }]
    )
